// Extraer datos del mensaje entrante
const body = $input.first().json.body || $input.first().json;
const simulation = body._simulation || body;

// Datos del mensaje
const message = simulation.message || '';
const orderId = simulation.order_id || '';
const buyerName = simulation.buyer?.first_name || 'Cliente';
const buyerId = simulation.buyer?.id || '';

// Datos del producto
const productTitle = simulation.product?.title || '';
const productSku = simulation.product?.sku || '';
const productPrice = simulation.product?.price || 0;

// Datos del envio
const shippingStatus = simulation.shipping?.status || 'unknown';
const trackingNumber = simulation.shipping?.tracking_number || '';
const carrier = simulation.shipping?.carrier || '';
const dateDelivered = simulation.shipping?.date_delivered || null;

// Datos de facturacion
const docType = simulation.billing?.doc_type || 'DNI';
const canReceiveFacturaA = simulation.billing?.can_receive_factura_a || false;

// Calcular dias desde entrega
let daysSinceDelivery = null;
if (dateDelivered) {
  const delivered = new Date(dateDelivered);
  const now = new Date();
  daysSinceDelivery = Math.floor((now - delivered) / (1000 * 60 * 60 * 24));
}

// Detectar tipo de consulta
const msgLower = message.toLowerCase();
let queryType = 'general';
let toolToUse = null;

if (msgLower.includes('donde') && (msgLower.includes('pedido') || msgLower.includes('envio') || msgLower.includes('paquete'))) {
  queryType = 'tracking';
  toolToUse = 'tracking_lookup';
} else if (msgLower.includes('factura')) {
  queryType = 'facturacion';
  toolToUse = 'billing_check';
} else if (msgLower.includes('devol') || msgLower.includes('reembolso')) {
  queryType = 'devolucion';
  toolToUse = 'return_policy_check';
} else if (msgLower.includes('garantia') || msgLower.includes('falla') || msgLower.includes('defecto') || msgLower.includes('roto')) {
  queryType = 'garantia';
  toolToUse = 'warranty_check';
} else if (msgLower.includes('instala') || msgLower.includes('armar') || msgLower.includes('configur')) {
  queryType = 'instalacion';
  toolToUse = 'knowledge_base';
} else if (msgLower.includes('gracias') || msgLower.includes('excelente') || msgLower.includes('genial')) {
  queryType = 'agradecimiento';
  toolToUse = null;
}

return {
  json: {
    // Datos originales
    rawMessage: message,
    orderId,
    buyerName,
    buyerId,

    // Producto
    product: {
      title: productTitle,
      sku: productSku,
      price: productPrice
    },

    // Envio
    shipping: {
      status: shippingStatus,
      trackingNumber,
      carrier,
      dateDelivered,
      daysSinceDelivery
    },

    // Facturacion
    billing: {
      docType,
      canReceiveFacturaA
    },

    // Analisis
    queryType,
    toolToUse,

    // Para el prompt
    contextForAI: `
Cliente: ${buyerName}
Producto: ${productTitle} (${productSku})
Precio: $${productPrice?.toLocaleString()}
Estado envio: ${shippingStatus}
Tracking: ${trackingNumber || 'N/A'}
Dias desde entrega: ${daysSinceDelivery !== null ? daysSinceDelivery : 'No entregado'}
Tipo doc: ${docType}
Puede Factura A: ${canReceiveFacturaA ? 'Si' : 'No'}
Tipo consulta detectada: ${queryType}
`
  }
};

// Generar respuesta de tracking
const data = $input.first().json;
const shipping = data.shipping;
const buyerName = data.buyerName;
const productTitle = data.product.title;

let response = '';

switch (shipping.status) {
  case 'delivered':
    response = `Hola ${buyerName}! Tu pedido de ${productTitle} ya fue entregado hace ${shipping.daysSinceDelivery} dias. Si no lo recibiste o tenes algun problema, por favor avisanos para ayudarte.`;
    break;
  case 'in_transit':
    response = `Hola ${buyerName}! Tu pedido de ${productTitle} esta en camino. El numero de seguimiento es ${shipping.trackingNumber || 'pendiente de asignacion'}. Podes seguirlo desde la app. La entrega estimada es en los proximos 2-3 dias habiles.`;
    break;
  case 'pending':
    response = `Hola ${buyerName}! Tu pedido de ${productTitle} esta siendo preparado en nuestro deposito. En las proximas 24-48hs te enviamos el numero de seguimiento. Gracias por tu paciencia!`;
    break;
  case 'shipped':
    response = `Hola ${buyerName}! Tu pedido de ${productTitle} ya salio de nuestro deposito! El tracking es ${shipping.trackingNumber}. Transportista: ${shipping.carrier}. Seguilo en tiempo real desde la app.`;
    break;
  default:
    response = `Hola ${buyerName}! Dejame verificar el estado de tu pedido de ${productTitle}. En breve te doy una actualizacion.`;
}

return {
  json: {
    ...data,
    aiResponse: response,
    toolUsed: 'tracking_lookup',
    shouldEscalate: false
  }
};

// Generar respuesta de facturacion
const data = $input.first().json;
const billing = data.billing;
const buyerName = data.buyerName;
const productTitle = data.product.title;

let response = '';
let shouldEscalate = false;

if (data.rawMessage.toLowerCase().includes('factura a')) {
  if (billing.canReceiveFacturaA) {
    response = `Hola ${buyerName}! Revise tus datos y confirmo que te corresponde Factura A por tu compra de ${productTitle}. La estamos generando y te la enviamos por email en las proximas 24-48hs habiles. Si necesitas que la enviemos a otro mail, avisame!`;
  } else {
    response = `Hola ${buyerName}! Vi que pedis Factura A, pero segun tus datos registrados (${billing.docType}), corresponde Factura B para Consumidor Final. Si sos monotributista o responsable inscripto, por favor envianos tu CUIT y razon social para actualizar la facturacion.`;
  }
} else {
  response = `Hola ${buyerName}! Tu factura por la compra de ${productTitle} se genera automaticamente y se envia por email. Si necesitas Factura A, indicame tu CUIT y condicion fiscal.`;
}

return {
  json: {
    ...data,
    aiResponse: response,
    toolUsed: 'billing_check',
    shouldEscalate
  }
};

// Generar respuesta de devolucion
const data = $input.first().json;
const shipping = data.shipping;
const buyerName = data.buyerName;
const productTitle = data.product.title;

let response = '';
let shouldEscalate = false;

const daysSinceDelivery = shipping.daysSinceDelivery;

if (daysSinceDelivery !== null && daysSinceDelivery <= 30) {
  response = `Hola ${buyerName}! Entiendo que queres devolver ${productTitle}. Como la compra tiene ${daysSinceDelivery} dias desde la entrega, estas dentro del plazo de devolucion (30 dias). Para proceder, necesito saber: El producto esta en su empaque original? Esta en las mismas condiciones que lo recibiste?`;
  shouldEscalate = true; // Devoluciones siempre escalan para revision humana
} else if (daysSinceDelivery !== null && daysSinceDelivery > 30) {
  response = `Hola ${buyerName}! Lamentablemente el plazo de devolucion por arrepentimiento (30 dias) ya vencio para tu compra de ${productTitle} (hace ${daysSinceDelivery} dias). Sin embargo, si el producto tiene algun defecto, la garantia de 6 meses sigue vigente. Contame que paso con el producto?`;
} else {
  response = `Hola ${buyerName}! Para ayudarte con la devolucion de ${productTitle}, necesito verificar el estado de tu pedido. Dame un momento...`;
  shouldEscalate = true;
}

return {
  json: {
    ...data,
    aiResponse: response,
    toolUsed: 'return_policy_check',
    shouldEscalate
  }
};

// Generar respuesta de garantia
const data = $input.first().json;
const shipping = data.shipping;
const buyerName = data.buyerName;
const productTitle = data.product.title;

let response = '';
let shouldEscalate = true; // Garantias siempre escalan

const daysSinceDelivery = shipping.daysSinceDelivery;

if (daysSinceDelivery !== null && daysSinceDelivery <= 180) {
  response = `Hola ${buyerName}! Lamento escuchar que tenes un problema con ${productTitle}. El producto tiene garantia de 6 meses y estas dentro del plazo (${daysSinceDelivery} dias desde la entrega). Para ayudarte, necesito que me cuentes: Cual es el problema especifico? Si podes, enviame fotos o un video del defecto para documentar el caso y agilizar el proceso de garantia.`;
} else if (daysSinceDelivery !== null && daysSinceDelivery > 180) {
  response = `Hola ${buyerName}! El periodo de garantia de 6 meses (180 dias) ya finalizo para tu ${productTitle} (hace ${daysSinceDelivery} dias). De todas formas, contame que problema tenes y vemos si hay alguna solucion que podamos ofrecerte.`;
  shouldEscalate = true;
} else {
  response = `Hola ${buyerName}! Para ayudarte con la garantia de ${productTitle}, contame que problema tenes con el producto?`;
}

return {
  json: {
    ...data,
    aiResponse: response,
    toolUsed: 'warranty_check',
    shouldEscalate,
    escalationReason: 'Reclamo de garantia - requiere evaluacion tecnica'
  }
};

// Generar respuesta generica o agradecimiento
const data = $input.first().json;
const buyerName = data.buyerName;
const productTitle = data.product.title;
const queryType = data.queryType;

let response = '';

if (queryType === 'agradecimiento') {
  response = `Hola ${buyerName}! Muchas gracias por tu mensaje! Nos alegra mucho saber que estas conforme. Si en el futuro necesitas algo mas o tenes alguna consulta sobre ${productTitle}, estamos para ayudarte. Buen gaming! 🎮`;
} else if (queryType === 'instalacion') {
  response = `Hola ${buyerName}! Con gusto te ayudo con la instalacion/configuracion de ${productTitle}. Contame especificamente que necesitas saber o en que paso estas trabado y te guio paso a paso.`;
} else {
  response = `Hola ${buyerName}! Gracias por escribirnos. Estoy revisando tu consulta sobre ${productTitle}. En que puedo ayudarte especificamente?`;
}

return {
  json: {
    ...data,
    aiResponse: response,
    toolUsed: queryType === 'instalacion' ? 'knowledge_base' : null,
    shouldEscalate: false
  }
};

// Preparar respuesta final
const data = $input.first().json;

return {
  json: {
    output: data.aiResponse,
    toolUsed: data.toolUsed,
    escalated: data.shouldEscalate,
    queryType: data.queryType,
    metadata: {
      orderId: data.orderId,
      buyerName: data.buyerName,
      product: data.product.title
    }
  }
};
